14→const BasicScreen: FC<BasicScreenProps> = ({
15→  hasNativeGoBack = true,
16→  nativeGoBackFn,
17→  ...props
18→}) => {
19→  const navigation = useNavigation<NavigationProp<PropsRootStack>>();
20→
21→  const currentRouteName = useNavigationState(state => {
22→    const route = state.routes[state.index];
23→    return route.name;
24→  });
25→
26→  const nativeGoBackHandler = useCallback(() => {
27→    if (!hasNativeGoBack) return true;
28→
29→    if (nativeGoBackFn) {
30→      nativeGoBackFn();
31→      return true;
32→    }
33→  }, [
34→    hasNativeGoBack,
35→    nativeGoBackFn,
36→  ]);
37→
38→  const handleGoToHome = () => {
39→    navigation.navigate('HomeScreen' as never);
40→  };
41→
42→  useEffect(() => {
43→    if (props.hasError) {
44→      eventModalView({
45→        content_id: `erro_generico_${currentRouteName}`,
46→        screen_bussines: 'monetizacao',
47→        location_1: 'monetizacao',
48→        location_2: 'spmais',
49→        location_3: currentRouteName,
50→      });
51→    }
52→    // eslint-disable-next-line react-hooks/exhaustive-deps
53→  }, [props.hasError]);
54→
55→  useEffect(() => {
56→    const backHandler = BackHandler.addEventListener(
57→      'hardwareBackPress',
58→      nativeGoBackHandler,
59→    );
60→
61→    return () => backHandler.remove();
62→  }, [nativeGoBackHandler]);
63→
64→  return (
65→    <BasicScreenView
66→      handleGoToHome={handleGoToHome}
67→      currentRouteName={currentRouteName}
68→      {...props}
69→    />
70→  );
71→};
72→
73→export default BasicScreen;
